var e=[{id:`L2_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`헉! 체육복을 안 챙겨왔잖아?`,JPN:`あっ！　体操服忘れちゃった……`,ENG:`Ah! I forgot my gym clothes!`,TWN:`慘了！我沒帶運動服！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`음, 옆반에서 빌려야 하나......?`,JPN:`う～ん、隣のクラスの子に借りようかな？`,ENG:`Hmm, should I borrow one from someone else?`,TWN:`嗯，要去跟隔壁班借嗎……？`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`앗! 갑자기 소나기가 내려!`,JPN:`あっ、雨だ！`,ENG:`Ah! It's raining!`,TWN:`啊！突然下起來了雷陣雨！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`소나기라고? 이 한겨울에?`,JPN:`雨？　そしたら今日の体育は……`,ENG:`Rain shower? In the middle of the winter?`,TWN:`雷陣雨？在這隆冬的時候？`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`TEACHER_EXTRA_F_NULL`,text:{KOREA:`자, 오늘 체육은 실내자습으로 대체한다.`,JPN:`今日の体育は室内自習に変更だ。`,ENG:`Alright, we're going to replace today's P.E. with an indoor study hall.`,TWN:`那麼，今天的體育課就改成室內自習吧。`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`안 돼요! 축구공도 다 꺼내 놨는데!`,JPN:`そんな～！　サッカーボール用意したのに……`,ENG:`No! We already got the soccer ball ready!`,TWN:`不會吧！我都把足球拿出來了耶！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`너무해!`,JPN:`先生、ひどいよ～！`,ENG:`That sucks!`,TWN:`太過分了！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`TEACHER_EXTRA_F_NULL`,text:{KOREA:`그럼 비 맞으면서 뛸 거니? 소란 떨지 말고 교실로 들어가.`,JPN:`じゃあ、雨の中で走り回りたいのか？
バカなこと言ってないで教室に戻れ。`,ENG:`Then are you going to run around in the rain? Stop making a fuss and go back to the classroom.`,TWN:`難道你要淋著雨踢球嗎？別吵了，快進教室去。`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`헤헤, 다행이다......`,JPN:`へへッ、助かった～。`,ENG:`Heh, that's a relief...`,TWN:`嘿嘿，太好了……`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`뭔 소나기가 하교시간까지 계속 내리냐?`,JPN:`もう下校時間だっていうのに、まだ降ってるわけ？`,ENG:`Why is it still raining after school?`,TWN:`這什麼雷陣雨，居然一直下到放學？`},stage:{bg:`CLASS`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`이러다가 홍수 나겠네.`,JPN:`このままじゃ、大洪水だな。`,ENG:`We're going to have a flood at this rate.`,TWN:`這樣下去會淹水吧。`},stage:{bg:`CLASS`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`아, 모르겠다. 나 먼저 간다! 내일 봐!`,JPN:`あ～もういいや。じゃあ、また明日！`,ENG:`Ah, whatever. I'm heading out first! See you tomorrow!`,TWN:`算了，不管了。我先走了！明天見！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`윽, 그러고 보니 오늘 우산도 안 가지고 왔는데.`,JPN:`うっ、そういえば今日は傘も忘れたんだった。`,ENG:`Aw, I didn't bring my umbrella today.`,TWN:`嗚，這麼說來，今天我也沒帶傘。`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`나도 뛰어가야 하나?`,JPN:`私も走って行くしかないのかな？`,ENG:`Should I make a run for it as well?`,TWN:`我也要跑回家嗎？`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`야, 거기서! 나도 우산 하나 밖에 없다고!`,JPN:`ちょっと待って！　私も傘が一つしかないんだから！`,ENG:`Hey, stop! I only have one umbrella!`,TWN:`喂，站住！我只有一把傘啦！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`케케, 잡을 수 있으면 잡아보던가!`,JPN:`捕まえられるもんなら、捕まえてみろ～！`,ENG:`Hah hah, catch me if you can!`,TWN:`嘿嘿，有本事的話來抓我啊！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`STUDENT_EXTRA_NULL_NULL`,text:{KOREA:`아야야......!`,JPN:`イタタ～！`,ENG:`Ow!`,TWN:`唉呀呀……！`},stage:{bg:`CLASS`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};